{"code": "import json
import re

# Reload data
reviews_file = locals()['var_functions.query_db:18']
with open(reviews_file, 'r') as f:
    reviews_from_2016_users = json.load(f)

businesses = locals()['var_functions.query_db:58']

# Extract categories for all 5 businesses
biz_categories = {}
for b in businesses:
    ref = b['business_id'].replace('businessid_', 'businessref_')
    desc = b.get('description', '')

    cats = []
    if 'services in' in desc:
        match = re.search(r'services in (.+?)(?:\.|$)', desc)
        if match:
            cats = [c.strip() for c in re.sub(r',? and ', ', ', match.group(1)).split(',') if c.strip()]
    elif 'including' in desc:
        match = re.search(r'including (.+?)(?:\.|$)', desc)
        if match:
            cats = [c.strip() for c in re.sub(r',? and ', ', ', match.group(1)).split(',') if c.strip()]

    biz_categories[ref] = cats

# Count reviews by category and track business matches
review_counts = {}
business_matches = {}
matched_reviews = 0

for review in reviews_from_2016_users:
    biz_ref = review['business_ref']
    if biz_ref in biz_categories:
        matched_reviews += 1
        business_matches[biz_ref] = business_matches.get(biz_ref, 0) + 1

        for cat in biz_categories[biz_ref]:
            review_counts[cat] = review_counts.get(cat, 0) + 1

# Sort categories by review count
top_categories = sorted(review_counts.items(), key=lambda x: x[1], reverse=True)

# Get business names for context
biz_names = {b['business_id'].replace('businessid_', 'businessref_'): b['name'] for b in businesses}

print('__RESULT__:')
print(json.dumps({
    'total_reviews_from_2016_users': len(reviews_from_2016_users),
    'reviews_matched_to_available_businesses': matched_reviews,
    'percentage_matched': round(matched_reviews / len(reviews_from_2016_users) * 100, 2),
    'available_businesses': len(biz_categories),
    'categories_and_reviews': top_categories,
    'business_match_details': {ref: {'name': biz_names[ref], 'reviews': count, 'categories': biz_categories[ref]} 
                              for ref, count in business_matches.items()}
}, indent=2))"}

